import{_ as a,o as i,c as n,a2 as e}from"./chunks/framework.Crpw6aS5.js";const b=JSON.parse('{"title":"GDB attach 时加载带调试信息的共享库符号","description":"","frontmatter":{},"headers":[],"relativePath":"5 工具/GDB attach加载带调试信息的共享库符号.md","filePath":"5 工具/GDB attach加载带调试信息的共享库符号.md","lastUpdated":1778478297000}'),l={name:"5 工具/GDB attach加载带调试信息的共享库符号.md"};function t(p,s,d,r,o,h){return i(),n("div",null,[...s[0]||(s[0]=[e(`<h1 id="gdb-attach-时加载带调试信息的共享库符号" tabindex="-1">GDB attach 时加载带调试信息的共享库符号 <a class="header-anchor" href="#gdb-attach-时加载带调试信息的共享库符号" aria-label="Permalink to &quot;GDB attach 时加载带调试信息的共享库符号&quot;">​</a></h1> <h2 id="问题" tabindex="-1">问题 <a class="header-anchor" href="#问题" aria-label="Permalink to &quot;问题&quot;">​</a></h2> <p>进程运行时链接的是 stripped 的共享库（无调试信息），attach 后无法查看库函数的源码和断点信息。需要让 GDB 使用另一份带调试信息的 so 来加载符号。</p> <p>以 libzmq 为例：进程加载的是 <code>/lib/aarch64-linux-gnu/libzmq.so.5</code>（无调试信息），而 <code>/home/data/libzmq/</code> 下有编译时保留调试信息的版本。</p> <h2 id="关键认知" tabindex="-1">关键认知 <a class="header-anchor" href="#关键认知" aria-label="Permalink to &quot;关键认知&quot;">​</a></h2> <p><strong>GDB attach 不能改变进程的库加载路径。</strong> 进程启动时 <code>execve</code> 和动态链接器已完成路径解析，<code>/proc/&lt;pid&gt;/maps</code> 中的映射不可更改。GDB 能做的只是<strong>替换符号文件的查找来源</strong>。</p> <h2 id="方案对比" tabindex="-1">方案对比 <a class="header-anchor" href="#方案对比" aria-label="Permalink to &quot;方案对比&quot;">​</a></h2> <table tabindex="0"><thead><tr><th>方案</th> <th>原理</th> <th>优缺点</th></tr></thead> <tbody><tr><td><code>set solib-search-path</code></td> <td>按文件名在指定目录搜索符号文件</td> <td>仅在原始路径文件不存在时回退搜索，本地文件存在时无效</td></tr> <tr><td><code>set sysroot</code></td> <td>路径前缀重定向</td> <td>需要构造完整目录结构，影响所有库的查找</td></tr> <tr><td><code>add-symbol-file</code></td> <td>手动指定符号文件和加载地址</td> <td>最直接，不影响其他库，推荐</td></tr> <tr><td>临时替换原文件</td> <td>替换系统目录下的 so</td> <td>暴力有效，但影响全局，需恢复</td></tr></tbody></table> <h2 id="推荐方案-add-symbol-file" tabindex="-1">推荐方案：add-symbol-file <a class="header-anchor" href="#推荐方案-add-symbol-file" aria-label="Permalink to &quot;推荐方案：add-symbol-file&quot;">​</a></h2> <h3 id="步骤" tabindex="-1">步骤 <a class="header-anchor" href="#步骤" aria-label="Permalink to &quot;步骤&quot;">​</a></h3> <ol><li><strong>查看目标库的加载地址</strong></li></ol> <div class="language-gdb vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">gdb</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>(gdb) info sharedlibrary libzmq</span></span>
<span class="line"><span>From                To                  Syms Read  Shared Object Library</span></span>
<span class="line"><span>0x0000ffffa18124e0  0x0000ffffa186f344  Yes (*)    /lib/aarch64-linux-gnu/libzmq.so.5</span></span></code></pre> <div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>起始地址 <code>0x0000ffffa18124e0</code> 即 .text 段地址。</p> <ol start="2"><li><strong>加载带调试信息的符号文件</strong></li></ol> <div class="language-gdb vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">gdb</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>(gdb) add-symbol-file /home/data/libzmq/libzmq.so.5 0x0000ffffa18124e0</span></span>
<span class="line"><span>add symbol table from file &quot;/home/data/libzmq/libzmq.so.5&quot; at</span></span>
<span class="line"><span>    .text_addr = 0xffffa18124e0</span></span>
<span class="line"><span>(y or n) y</span></span>
<span class="line"><span>Reading symbols from /home/data/libzmq/libzmq.so.5...</span></span></code></pre> <div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><ol start="3"><li><strong>验证符号加载成功</strong></li></ol> <div class="language-gdb vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">gdb</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>(gdb) info functions zmq_send</span></span>
<span class="line"><span>All functions matching regular expression &quot;zmq_send&quot;:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>File /home/user/workspace/libzmq/src/zmq.cpp:</span></span>
<span class="line"><span>356:    int zmq_send(void*, void const*, size_t, int);</span></span>
<span class="line"><span>383:    int zmq_send_const(void*, void const*, size_t, int);</span></span>
<span class="line"><span>415:    int zmq_sendiov(void*, iovec*, size_t, int);</span></span>
<span class="line"><span>351:    int zmq_sendmsg(void*, zmq_msg_t*, int);</span></span></code></pre> <div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>能列出源码位置和函数签名，说明符号生效。</p> <ol start="4"><li><strong>正常调试</strong></li></ol> <div class="language-gdb vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">gdb</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>(gdb) b zmq_send</span></span>
<span class="line"><span>(gdb) b zmq.cpp:356</span></span>
<span class="line"><span>(gdb) list zmq_send</span></span></code></pre> <div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h3 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to &quot;注意事项&quot;">​</a></h3> <ul><li><code>info sharedlibrary</code> 中该库仍显示 <code>Yes (*)</code>，这是正常的——它反映的是进程原始加载的 so 的状态，不影响 <code>add-symbol-file</code> 附加的符号</li> <li>如果 <code>info functions</code> 找不到函数，说明指定的 so 本身也是 stripped 的，需要确认文件是否包含调试信息：</li></ul> <div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">readelf</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -S</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /home/data/libzmq/libzmq.so.5</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> debug</span></span></code></pre> <div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="solib-search-path-为什么无效" tabindex="-1">solib-search-path 为什么无效 <a class="header-anchor" href="#solib-search-path-为什么无效" aria-label="Permalink to &quot;solib-search-path 为什么无效&quot;">​</a></h2> <p><code>set solib-search-path</code> 的工作机制：</p> <ol><li>GDB 取进程已加载库的文件名（如 <code>libzmq.so.5</code>）</li> <li>先尝试原始绝对路径 <code>/lib/aarch64-linux-gnu/libzmq.so.5</code></li> <li><strong>只有原始路径文件不存在时</strong>，才回退到 <code>solib-search-path</code> 指定的目录搜索</li></ol> <p>由于 <code>/lib/aarch64-linux-gnu/libzmq.so.5</code> 在本地存在，GDB 直接使用了它，<code>solib-search-path</code> 被跳过。</p> <h2 id="sysroot-方案-备选" tabindex="-1">sysroot 方案（备选） <a class="header-anchor" href="#sysroot-方案-备选" aria-label="Permalink to &quot;sysroot 方案（备选）&quot;">​</a></h2> <p>当需要批量替换多个库的符号时，构造 sysroot 目录结构更高效：</p> <div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 构造与原始路径一致的目录结构</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mkdir</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /home/data/sysroot/lib/aarch64-linux-gnu/</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /home/data/libzmq/libzmq.so.5.2.2</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /home/data/sysroot/lib/aarch64-linux-gnu/</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /home/data/sysroot/lib/aarch64-linux-gnu/</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ln</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -sf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> libzmq.so.5.2.2</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> libzmq.so.5</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ln</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -sf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> libzmq.so.5</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> libzmq.so</span></span></code></pre> <div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><div class="language-gdb vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">gdb</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>(gdb) set sysroot /home/data/sysroot</span></span>
<span class="line"><span>(gdb) set solib-search-path /lib/aarch64-linux-gnu:/home/efort/lib</span></span></code></pre> <div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p><code>solib-search-path</code> 作为补充，让 GDB 能找到 sysroot 中未覆盖的其他库。</p> <h2 id="精确获取-text-段地址" tabindex="-1">精确获取 .text 段地址 <a class="header-anchor" href="#精确获取-text-段地址" aria-label="Permalink to &quot;精确获取 .text 段地址&quot;">​</a></h2> <p><code>info sharedlibrary</code> 显示的起始地址通常就是 .text 段地址。如需精确确认：</p> <div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /proc/</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">pi</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/maps</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> libzmq</span></span></code></pre> <div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>输出中 <code>r-xp</code>（可读可执行）权限的行即为 .text 段：</p> <div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ffffa18124e0-ffffa186f344 r-xp 00000000 ... /lib/aarch64-linux-gnu/libzmq.so.5</span></span></code></pre> <div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h2> <ul><li><strong>attach 后无法改变进程的库加载路径</strong>，只能替换 GDB 的符号查找来源</li> <li><strong><code>add-symbol-file</code> 是最干净的方案</strong>：一行命令，不影响其他库，不需要修改任何文件</li> <li><code>info sharedlibrary</code> 的 <code>(*)</code> 标记不影响实际调试，以 <code>info functions</code> 和断点设置验证为准</li> <li><code>solib-search-path</code> 在原始路径文件存在时不会生效，这是最常见的踩坑点</li></ul>`,68)])])}const m=a(l,[["render",t]]);export{b as __pageData,m as default};
